module RefModule(
    input [7:0]A,
    input [7:0]B,
    output [7:0] Sum,
    output Overflow
    );reg[8:0] tempSum;
	reg unused_tempOv;

	always @(A or B)
	  begin
		 tempSum = A + B;
		 unused_tempOv = tempSum[8];
	  end

  assign Sum = tempSum;
  assign Overflow = unused_tempOv;




endmodule
